32	struct CubinId {
33	    unsigned char bytes[32];
34	
35	    bool operator==(const CubinId& o) const {
36	        for (size_t i = 0; i < sizeof(bytes); ++i)
37	            if (bytes[i] != o.bytes[i]) return false;
38	        return true;
39	    }
40	};
41	
42	
43	template <>
44	struct Hash<CubinId> {
45	    static void hash(const CubinId& k, Hasher& h) {
46	        // SHA-256 output is already uniform; one 64-bit word is enough entropy.
47	        uint64_t v;
48	        mem_copy(&v, k.bytes, sizeof(v));
49	        h.hash(v);
50	    }
51	};
