57	XLA_FFI_Error* xla_error(const XLA_FFI_Api* api,
58	                         XLA_FFI_Error_Code code,
59	                         const char* fmt, va_list ap) {
60	  char buf[512];
61	  PyOS_vsnprintf(buf, sizeof(buf), fmt, ap);
