80	// =============== Kernel registry ===================
81	// `KernelEntry` owns the cuLibrary and cuKernel, with a
82	// reference count of how many `CutileCallState`s currently reference it.
83	// Every populated entry starts at refcount=1 (the constructing call
84	// state's reference); the registry owns these via heap allocation.
85	// `~KernelEntry` unloads the library best-effort.
86	struct KernelEntry {
87	    CUlibrary  lib = nullptr;
88	    CUkernel kernel = nullptr;
89	    size_t    refcount = 0;
90	
91	    KernelEntry(CUlibrary l, CUkernel k) : lib(l), kernel(k), refcount(1) {}
92	    KernelEntry(const KernelEntry&) = delete;
93	    KernelEntry& operator=(const KernelEntry&) = delete;
94	    ~KernelEntry() {
95	        if (!lib) return;
96	        Result<const DriverApi*> d = get_driver_api();
97	        if (d.is_ok()) (*d)->cuLibraryUnload(lib);
98	    }
99	};
100	
101	struct KernelRegistry {
102	#ifdef Py_GIL_DISABLED
103	    PyMutex m = {0};
104	#endif
105	    // Slot value is nullptr after the last referent is destroyed. Future
106	    // registrations of the same cubin_id repopulate the same slot.
107	    HashMap<CubinId, KernelEntry*> map;
108	};
109	
110	static KernelRegistry* g_kernel_registry = new KernelRegistry();
