113	// =============== Call State ===================
114	// Owns a +1 refcount on `entry`; ~CutileCallState releases it and (when
115	// the count hits zero) unloads the cubin and nulls the registry slot.
116	struct CutileCallState {
117	  static XLA_FFI_TypeId id;
118	
119	  const DriverApi* d = nullptr;
120	  KernelEntry* entry = nullptr;
121	  CubinId cubin_id = {};
122	  int32_t   num_inputs   = 0;
123	  int32_t   num_outputs  = 0;
124	  int32_t   grid_x       = 0;
125	  int32_t   grid_y       = 0;
126	  int32_t   grid_z       = 0;
127	  // Per kernel-arg position, the index into the FFI-side buffer list
128	  // (inputs first, then outputs, then scalar_packed).
129	  Vec<int32_t> buffer_ids;
130	  // Index bitwidth (32 or 64) the kernel was compiled with for the
131	  // corresponding buffer. Parallel to `buffer_ids`.
132	  Vec<int32_t> index_bitwidths;
133	  // Packed scalar argument: each entry is the raw 64-bit bit pattern of a
134	  // runtime scalar (zero-padded high bits when the dtype is narrower).
135	  // Cast into a Word at execute time.
136	  Vec<uint64_t> scalar_packed;
137	
138	  ~CutileCallState() {
139	      if (!entry) return;
140	      GILGuard g;
141	#ifdef Py_GIL_DISABLED
142	      PyCriticalSectionGuard guard(&g_kernel_registry->m);
143	#endif
144	      if (--entry->refcount == 0) {
145	          delete entry;
146	          if (auto* item = g_kernel_registry->map.find(cubin_id))
147	              item->value = nullptr;
148	      }
149	  }
150	};
