182	XLA_FFI_Error* get_state(const XLA_FFI_Api* api,
183	                         XLA_FFI_ExecutionContext* ctx,
184	                         XLA_FFI_ExecutionStage stage,
185	                         StateType** out) {
186	  XLA_FFI_State_Get_Args args = {
187	      .struct_size = XLA_FFI_State_Get_Args_STRUCT_SIZE,
