239	// ============== Attr Decode Helper ===============
240	
241	static const XLA_FFI_ByteSpan* attr_string(const XLA_FFI_Attrs* attrs, size_t idx) {
242	    if (idx >= static_cast<size_t>(attrs->size)) return nullptr;
243	    if (attrs->types[idx] != XLA_FFI_AttrType_STRING) return nullptr;
244	    return static_cast<const XLA_FFI_ByteSpan*>(attrs->attrs[idx]);
245	}
246	
247	static const XLA_FFI_Scalar* attr_scalar(const XLA_FFI_Attrs* attrs, size_t idx) {
248	    if (idx >= static_cast<size_t>(attrs->size)) return nullptr;
249	    if (attrs->types[idx] != XLA_FFI_AttrType_SCALAR) return nullptr;
250	    return static_cast<const XLA_FFI_Scalar*>(attrs->attrs[idx]);
251	}
252	
253	static const XLA_FFI_Array* attr_array(const XLA_FFI_Attrs* attrs, size_t idx) {
254	    if (idx >= static_cast<size_t>(attrs->size)) return nullptr;
255	    if (attrs->types[idx] != XLA_FFI_AttrType_ARRAY) return nullptr;
256	    return static_cast<const XLA_FFI_Array*>(attrs->attrs[idx]);
257	}
258	
259	template <typename T>
260	static bool read_scalar(const XLA_FFI_Attrs* attrs, size_t idx,
261	                        XLA_FFI_DataType expected, T* out) {
262	    const XLA_FFI_Scalar* s = attr_scalar(attrs, idx);
263	    if (!s || s->dtype != expected) return false;
264	    *out = *static_cast<const T*>(s->value);
265	    return true;
266	}
