269	// Loads `code` into context independent CUlibrary + CUKernel
270	// and returns a heap-allocated KernelEntry (refcount=1).
271	static void format_sha256_hex(const CubinId& k, char out[65]) {
272	    static const char kHex[] = "0123456789abcdef";
273	    for (size_t i = 0; i < sizeof(k.bytes); ++i) {
274	        out[2*i]     = kHex[(k.bytes[i] >> 4) & 0xF];
275	        out[2*i + 1] = kHex[k.bytes[i] & 0xF];
276	    }
277	    out[64] = '\0';
278	}
279	
280	KernelEntry* load_kernel(const XLA_FFI_Api* api, const DriverApi* d,
281	                         const CubinId& cubin_id,
282	                         const XLA_FFI_ByteSpan* code,
283	                         const XLA_FFI_ByteSpan* function,
284	                         XLA_FFI_Error** err_out) {
285	    CUlibrary lib = nullptr;
286	    CUresult rc = d->cuLibraryLoadData(&lib, code->ptr, nullptr, nullptr, 0, nullptr, nullptr, 0);
287	    if (rc != CUDA_SUCCESS) {
288	        char hex[65];
289	        format_sha256_hex(cubin_id, hex);
290	        *err_out = xla_internal_error(api,
291	            "LoadData failed for cubin_id=%s (rc=%d)",
292	            hex, static_cast<int>(rc));
293	        return nullptr;
294	    }
295	
296	    // ByteSpan is not NULL-terminated; copy into a null-terminated scratch.
297	    Vec<char> name_buf(function->len + 1);
298	    mem_copy(name_buf.data(), function->ptr, function->len);
299	    name_buf[function->len] = '\0';
300	
301	    CUkernel cukernel = nullptr;
302	    rc = d->cuLibraryGetKernel(&cukernel, lib, name_buf.data());
303	    if (rc != CUDA_SUCCESS) {
304	        d->cuLibraryUnload(lib);
305	        *err_out = xla_internal_error(api,
306	            "GetKernel failed for %s (rc=%d)",
307	            name_buf.data(), static_cast<int>(rc));
308	        return nullptr;
309	    }
310	    return new KernelEntry(lib, cukernel);
311	}
