313	
314	// ============= cuTile Call Handler =================================
315	// Attrs (alphabetical):
316	//   buffer_ids, cubin_code, cubin_id, function_name, grid_x, grid_y,
317	//   grid_z, index_bitwidths, num_inputs, num_outputs, scalar_packed.
318	enum : size_t {
319	    kCall_buffer_ids = 0,
320	    kCall_cubin_code,
321	    kCall_cubin_id,
322	    kCall_function_name,
323	    kCall_grid_x,
324	    kCall_grid_y,
325	    kCall_grid_z,
326	    kCall_index_bitwidths,
327	    kCall_num_inputs,
328	    kCall_num_outputs,
329	    kCall_scalar_packed,
330	};
331	
332	XLA_FFI_Error* cutile_call_instantiate(XLA_FFI_CallFrame* cf) {
333	    GILGuard g;
334	#ifdef Py_GIL_DISABLED
335	    PyCriticalSectionGuard guard(&g_kernel_registry->m);
336	#endif
337	    Result<const DriverApi*> driver_result = get_driver_api();
338	    if (!driver_result.is_ok())
339	        return xla_internal_error(cf->api, "CUDA driver not available.");
340	    const DriverApi* d = *driver_result;
341	
342	    CubinId cubin_id = {};
343	    const XLA_FFI_Array* cubin_id_arr = attr_array(&cf->attrs, kCall_cubin_id);
344	    if (!cubin_id_arr || cubin_id_arr->dtype != XLA_FFI_DataType_U8
345	        || cubin_id_arr->size != sizeof(cubin_id.bytes))
346	        return xla_internal_error(cf->api,
347	            "cutile_call: missing/invalid cubin_id");
348	    mem_copy(cubin_id.bytes, cubin_id_arr->data, sizeof(cubin_id.bytes));
349	
350	    const XLA_FFI_ByteSpan* code = attr_string(&cf->attrs, kCall_cubin_code);
351	    if (!code) return xla_internal_error(cf->api,
352	            "cutile_call: missing cubin_code");
353	
354	    const XLA_FFI_ByteSpan* fn = attr_string(&cf->attrs, kCall_function_name);
355	    if (!fn) return xla_internal_error(cf->api,
356	            "cutile_call: missing function_name");
357	
358	    int32_t num_inputs = 0, num_outputs = 0;
359	    int32_t grid_x = 1, grid_y = 1, grid_z = 1;
360	    read_scalar(&cf->attrs, kCall_num_inputs,  XLA_FFI_DataType_S32, &num_inputs);
361	    read_scalar(&cf->attrs, kCall_num_outputs, XLA_FFI_DataType_S32, &num_outputs);
362	    read_scalar(&cf->attrs, kCall_grid_x,      XLA_FFI_DataType_S32, &grid_x);
363	    read_scalar(&cf->attrs, kCall_grid_y,      XLA_FFI_DataType_S32, &grid_y);
364	    read_scalar(&cf->attrs, kCall_grid_z,      XLA_FFI_DataType_S32, &grid_z);
365	
366	    const XLA_FFI_Array* bids = attr_array(&cf->attrs, kCall_buffer_ids);
367	    if (!bids || bids->dtype != XLA_FFI_DataType_S32)
368	        return xla_internal_error(cf->api, "cutile_call: missing/invalid buffer_ids");
369	
370	    const XLA_FFI_Array* ibws = attr_array(&cf->attrs, kCall_index_bitwidths);
371	    if (!ibws || ibws->dtype != XLA_FFI_DataType_S32 || ibws->size != bids->size)
372	        return xla_internal_error(cf->api,
373	            "cutile_call: missing/invalid index_bitwidths");
374	
375	    const XLA_FFI_Array* spk = attr_array(&cf->attrs, kCall_scalar_packed);
376	    if (!spk || spk->dtype != XLA_FFI_DataType_U64)
377	        return xla_internal_error(cf->api,
378	            "cutile_call: missing/invalid scalar_packed");
379	
380	    // Find-or-load the kernel entry and bump its refcount. The state below
381	    // owns this +1 ref and releases it on destruction.
382	    KernelEntry* entry = nullptr;
383	    {
384	        auto* item = g_kernel_registry->map.find(cubin_id);
385	        if (item && item->value) {
386	            entry = item->value;
387	            ++entry->refcount;
388	        } else {
389	            XLA_FFI_Error* error = nullptr;
390	            entry = load_kernel(cf->api, d, cubin_id, code, fn, &error);
391	            if (!entry) return error;
392	            if (item) {
393	                item->value = entry;  // resurrect dead slot
394	            } else {
395	                g_kernel_registry->map.insert(cubin_id, entry);
396	            }
397	        }
398	    }
399	
400	    auto* state = new CutileCallState();
401	    state->d = d;
402	    state->entry = entry;
403	    state->cubin_id = cubin_id;
404	    state->num_inputs = num_inputs;
405	    state->num_outputs = num_outputs;
406	    state->grid_x = grid_x;
407	    state->grid_y = grid_y;
408	    state->grid_z = grid_z;
409	    state->buffer_ids.resize(bids->size);
410	    mem_copy(state->buffer_ids.data(), bids->data, bids->size * sizeof(int32_t));
411	    state->index_bitwidths.resize(ibws->size);
412	    mem_copy(state->index_bitwidths.data(), ibws->data,
413	             ibws->size * sizeof(int32_t));
414	    state->scalar_packed.resize(spk->size);
415	    mem_copy(state->scalar_packed.data(), spk->data,
416	             spk->size * sizeof(uint64_t));
417	
418	    if (XLA_FFI_Error* err = set_state(cf->api, cf->ctx, cf->stage, state)) {
419	        // ~CutileCallState releases our refcount on the registry entry.
420	        delete state;
421	        return err;
422	    }
423	    return nullptr;
424	}
425	
426	
427	XLA_FFI_Error* cutile_call_initialize(XLA_FFI_CallFrame* cf) {
428	    CutileCallState* state = nullptr;
429	    if (XLA_FFI_Error* err = get_state(cf->api, cf->ctx, cf->stage, &state))
430	        return err;
431	
432	    const DriverApi* d = state->d;
433	    CUfunction f;
434	    // Ensure a context independent kernel is loaded into cuda context before execution stage.
435	    CUresult rc = d->cuKernelGetFunction(&f, state->entry->kernel);
436	    if (rc != CUDA_SUCCESS)
437	        return xla_internal_error(cf->api,
438	            "cuKernelGetFunction failed (rc=%d)", static_cast<int>(rc));
439	    return nullptr;
440	}
441	
442	
443	
444	union Word {
445	    void*   device_ptr;
446	    int32_t i32;
447	    int64_t i64;
448	    float   f32;
449	};
450	static_assert(sizeof(Word) == 8);
451	
452	// Pack one buffer into the cuTile-python-v1 calling convention:
453	//   1 Word for the device pointer, then ndim Words for shape, then ndim Words
454	//   for compact row-major strides (in elements, strides[ndim-1] = 1).
455	// Shape/stride are written to the full i64 lane: an i32-indexed kernel reads
456	// the low 4 bytes (correct for values < 2^31), an i64-indexed kernel reads
457	// all 8. When `index_bitwidth == 32` we refuse oversize values up front so
458	// the kernel can't silently read a truncated index.
459	static XLA_FFI_Error* pack_buffer(const XLA_FFI_Api* api,
460	                                  const XLA_FFI_Buffer* buf,
461	                                  int32_t index_bitwidth,
462	                                  Vec<Word>* cuargs) {
463	    constexpr int64_t kI32Max = (int64_t{1} << 31) - 1;
464	    const int64_t ndim = buf->rank;
465	    if (index_bitwidth == 32) {
466	        for (int64_t i = 0; i < ndim; ++i) {
467	            if (buf->dims[i] > kI32Max)
468	                return xla_internal_error(api,
469	                    "cutile_call: shape[%lld]=%lld exceeds the int32 index "
470	                    "range; annotate the kernel parameter with "
471	                    "ct.IndexedWithInt64",
472	                    (long long)i, (long long)buf->dims[i]);
473	        }
474	    }
475	
476	    cuargs->push_back({.device_ptr = buf->data});
477	
478	    for (int64_t i = 0; i < ndim; ++i) {
479	        Word w{};
480	        w.i64 = buf->dims[i];
481	        cuargs->push_back(w);
482	    }
483	
484	    // Row-major strides, computed back-to-front.
485	    size_t stride_base = cuargs->size();
486	    for (int64_t i = 0; i < ndim; ++i) {
487	        cuargs->push_back(Word{});
488	    }
489	    int64_t stride = 1;
490	    for (int64_t i = ndim - 1; i >= 0; --i) {
491	        if (index_bitwidth == 32 && stride > kI32Max)
492	            return xla_internal_error(api,
493	                "cutile_call: stride at dim %lld = %lld exceeds "
494	                "the int32 index range; annotate the kernel parameter with "
495	                "ct.IndexedWithInt64",
496	                (long long)i, (long long)stride);
497	        (*cuargs)[stride_base + i].i64 = stride;
498	        stride *= buf->dims[i];
499	    }
500	    return nullptr;
501	}
502	
503	XLA_FFI_Error* cutile_call_execute(XLA_FFI_CallFrame* cf) {
504	    CutileCallState* state = nullptr;
505	    if (XLA_FFI_Error* err = get_state(cf->api, cf->ctx, cf->stage, &state))
506	        return err;
507	
508	    void* stream_v = nullptr;
509	    if (XLA_FFI_Error* err = get_stream(cf->api, cf->ctx, &stream_v)) return err;
510	    CUstream stream = static_cast<CUstream>(stream_v);
511	
512	    const DriverApi* d = state->d;
513	
514	    // Pack each kernel-arg slot from its corresponding XLA buffer.
515	    Vec<Word> cuargs;
516	    for (size_t k = 0; k < state->buffer_ids.size(); ++k) {
517	        int32_t bid = state->buffer_ids[k];
518	        const XLA_FFI_Buffer* buf = nullptr;
519	        if (bid < state->num_inputs) {
520	            if (bid >= cf->args.size)
521	                return xla_internal_error(cf->api,
522	                    "buffer_ids[%zu]=%d out of range (args.size=%lld)",
523	                    k, bid, static_cast<long long>(cf->args.size));
524	            buf = static_cast<const XLA_FFI_Buffer*>(cf->args.args[bid]);
525	        } else if (bid < state->num_inputs + state->num_outputs) {
526	            int32_t ridx = bid - state->num_inputs;
527	            if (ridx >= cf->rets.size)
528	                return xla_internal_error(cf->api,
529	                    "buffer_ids[%zu]=%d out of range (rets.size=%lld)",
530	                    k, bid, static_cast<long long>(cf->rets.size));
531	            buf = static_cast<const XLA_FFI_Buffer*>(cf->rets.rets[ridx]);
532	        }
533	        if (buf) {
534	            int32_t ibw = state->index_bitwidths[k];
535	            if (XLA_FFI_Error* err = pack_buffer(cf->api, buf, ibw, &cuargs))
536	                return err;
537	        } else {
538	            // scalar argument
539	            int32_t ridx = bid - state->num_inputs - state->num_outputs;
540	            if (ridx < 0 || static_cast<size_t>(ridx) >= state->scalar_packed.size())
541	                return xla_internal_error(cf->api,
542	                    "buffer_ids[%zu]=%d out of range (scalar_packed.size=%lld)",
543	                    k, bid, static_cast<long long>(state->scalar_packed.size()));
544	            Word w{};
545	            w.i64 = static_cast<int64_t>(state->scalar_packed[ridx]);
546	            cuargs.push_back(w);
547	        }
548	    }
549	
550	    // cuLaunchKernel expects an array of pointers, one per kernel parameter.
551	    Vec<void*> cuarg_pointers;
552	    cuarg_pointers.reserve(cuargs.size());
553	    for (size_t i = 0; i < cuargs.size(); ++i) {
554	        cuarg_pointers.push_back(&cuargs[i]);
555	    }
556	
557	    CUresult rc = d->cuLaunchKernel(
558	        reinterpret_cast<CUfunction>(state->entry->kernel),
559	        state->grid_x, state->grid_y, state->grid_z,
560	        /*block=*/1, 1, 1,
561	        /*dynamic_shared_mem=*/0,
562	        stream,
563	        cuarg_pointers.data(),
564	        nullptr);
565	    if (rc != CUDA_SUCCESS)
566	        return xla_internal_error(cf->api,
567	            "cuLaunchKernel failed (rc=%d)", static_cast<int>(rc));
568	    return nullptr;
569	}
570	
571	}  // namespace
572	
573	
574	// =================== Exported handlers / accessors ========================
575	
576	XLA_FFI_Error* cutile_call_handler(XLA_FFI_CallFrame* cf) {
577	    if (is_metadata_query(cf)) {
578	        return populate_metadata(cf,
579	                XLA_FFI_HANDLER_TRAITS_COMMAND_BUFFER_COMPATIBLE,
580	                CutileCallState::id);
581	    }
582	    if (cf->stage == XLA_FFI_ExecutionStage_INSTANTIATE) {
583	        return cutile_call_instantiate(cf);
584	    } else if (cf->stage == XLA_FFI_ExecutionStage_INITIALIZE) {
585	        return cutile_call_initialize(cf);
586	    }
587	    if (cf->stage == XLA_FFI_ExecutionStage_EXECUTE) {
588	        return cutile_call_execute(cf);
589	    }
590	    return xla_internal_error(cf->api, "stage %d not implemented", cf->stage);
591	}
592	
593	
594	XLA_FFI_TypeId* cutile_call_state_type_id() {
595	    return &CutileCallState::id;
596	}
597	
598	const XLA_FFI_TypeInfo* cutile_call_state_type_info() {
599	    return &kCutileCallStateTypeInfo;
600	}
601	
602	#endif  // _WIN32
603

